// NewBluetoothSapStub creates a server-side IBluetoothSap wrapping the given
// server implementation. The returned value satisfies IBluetoothSap
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewBluetoothSapStub(
	impl IBluetoothSapServer,
) IBluetoothSap {
	wrapper := &bluetoothSapStubWrapper{impl: impl}
	stub := &BluetoothSapStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
